// frontend/src/pages/JS AIDashboard.js
import React, { useState, useEffect } from 'react';
import axios from 'axios';

const AIDashboard = () => {
  const [resumeText, setResumeText] = useState('');
  const [resumeCategory, setResumeCategory] = useState(null);
  const [recommendations, setRecommendations] = useState([]);
  const [loading, setLoading] = useState(false);
  const [aiStatus, setAiStatus] = useState('checking');
  
  const token = localStorage.getItem('token');
  const BACKEND_URL = 'http://localhost:5000';
  const AI_API_URL = 'http://localhost:5001';

  useEffect(() => {
    checkAIStatus();
    loadUserResume();
  }, []);

  const checkAIStatus = async () => {
    try {
      const response = await axios.get(`${AI_API_URL}/health`);
      setAiStatus(response.data.status === 'AI Service Running' ? 'online' : 'offline');
    } catch (error) {
      setAiStatus('offline');
    }
  };

  const loadUserResume = async () => {
    try {
      const response = await axios.get(`${BACKEND_URL}/api/applications`, {
        headers: { 'x-auth-token': token }
      });
      if (response.data && response.data.length > 0) {
        const text = response.data[0].resumeText || '';
        setResumeText(text);
        if (text) {
          analyzeResume(text);
        }
      }
    } catch (error) {
      console.error('Error loading resume:', error);
    }
  };

  const analyzeResume = async (text) => {
    setLoading(true);
    try {
      // Get category prediction
      const categoryRes = await axios.post(`${AI_API_URL}/predict/category`, {
        resume_text: text
      });
      setResumeCategory(categoryRes.data.predicted_category);

      // Sample job recommendations
      const jobs = [
        { id: 1, title: 'Software Engineer', description: 'Python, Django, React, SQL, AWS' },
        { id: 2, title: 'Data Scientist', description: 'Python, Machine Learning, SQL, Pandas' },
        { id: 3, title: 'Full Stack Developer', description: 'React, Node.js, MongoDB, JavaScript' },
        { id: 4, title: 'DevOps Engineer', description: 'AWS, Docker, Kubernetes, Jenkins' },
        { id: 5, title: 'HR Generalist', description: 'Recruitment, Employee Relations, HR policies' },
        { id: 6, title: 'Project Manager', description: 'Agile, Scrum, Leadership, Communication' }
      ];

      const matches = [];
      for (const job of jobs) {
        try {
          const matchRes = await axios.post(`${AI_API_URL}/predict/match`, {
            resume_text: text,
            job_description: job.description,
            job_title: job.title
          });
          matches.push({
            ...job,
            match_score: matchRes.data.match_score,
            match_level: matchRes.data.match_level,
            matching_skills: matchRes.data.matching_skills || 0,
            total_skills: matchRes.data.total_job_skills || 0
          });
        } catch (err) {
          console.error(`Error matching ${job.title}:`, err);
        }
      }
      setRecommendations(matches.sort((a, b) => b.match_score - a.match_score));
    } catch (error) {
      console.error('Analysis failed:', error);
    }
    setLoading(false);
  };

  const getMatchColor = (score) => {
    if (score >= 70) return '#28a745';
    if (score >= 50) return '#17a2b8';
    if (score >= 30) return '#ffc107';
    return '#dc3545';
  };

  const getMatchText = (score) => {
    if (score >= 70) return 'Excellent';
    if (score >= 50) return 'Good';
    if (score >= 30) return 'Fair';
    return 'Poor';
  };

  return (
    <div style={{ padding: '20px', maxWidth: '1200px', margin: '0 auto' }}>
      <h1>🤖 AI Career Dashboard</h1>

      {/* AI Status */}
      <div style={{
        padding: '10px',
        borderRadius: '5px',
        marginBottom: '20px',
        background: aiStatus === 'online' ? '#d4edda' : '#f8d7da',
        color: aiStatus === 'online' ? '#155724' : '#721c24'
      }}>
        {aiStatus === 'online' ? '✅ AI Service Connected' : '⚠️ AI Service Offline - Run python predict_api.py'}
      </div>

      {/* Resume Category */}
      {resumeCategory && (
        <div style={{
          background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
          color: 'white',
          padding: '20px',
          borderRadius: '10px',
          marginBottom: '20px',
          textAlign: 'center'
        }}>
          <h2>📊 Your Predicted Career Path</h2>
          <div style={{ fontSize: '32px', fontWeight: 'bold', marginTop: '10px' }}>
            {resumeCategory}
          </div>
          <p style={{ marginTop: '10px' }}>
            Based on your resume, AI predicts you're best suited for {resumeCategory} roles
          </p>
        </div>
      )}

      {/* Job Recommendations */}
      <h2>🎯 Recommended Jobs For You</h2>
      {loading ? (
        <div style={{ textAlign: 'center', padding: '50px' }}>
          <p>🤖 AI is analyzing your resume...</p>
        </div>
      ) : recommendations.length > 0 ? (
        <div style={{ display: 'grid', gap: '15px' }}>
          {recommendations.map((job) => (
            <div key={job.id} style={{
              border: `2px solid ${getMatchColor(job.match_score)}`,
              borderRadius: '10px',
              padding: '15px',
              cursor: 'pointer',
              transition: 'transform 0.2s'
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <h3 style={{ margin: 0 }}>{job.title}</h3>
                <div style={{ textAlign: 'right' }}>
                  <div style={{ fontSize: '24px', fontWeight: 'bold', color: getMatchColor(job.match_score) }}>
                    {job.match_score}%
                  </div>
                  <div style={{ fontSize: '12px', color: '#666' }}>Match Score</div>
                </div>
              </div>
              <div style={{ marginTop: '10px' }}>
                <span style={{
                  display: 'inline-block',
                  padding: '5px 10px',
                  borderRadius: '20px',
                  fontSize: '12px',
                  background: getMatchColor(job.match_score) + '20',
                  color: getMatchColor(job.match_score)
                }}>
                  {getMatchText(job.match_score)} Match
                </span>
                {job.matching_skills > 0 && (
                  <span style={{ marginLeft: '10px', fontSize: '12px', color: '#666' }}>
                    🎯 {job.matching_skills}/{job.total_skills} skills match
                  </span>
                )}
              </div>
              <p style={{ marginTop: '10px', color: '#666', fontSize: '14px' }}>
                {job.description}
              </p>
            </div>
          ))}
        </div>
      ) : (
        <div style={{ textAlign: 'center', padding: '50px', background: '#f8f9fa', borderRadius: '10px' }}>
          <p>📄 Upload a resume to see AI-powered job recommendations</p>
          <p style={{ fontSize: '12px', color: '#666' }}>Go to Dashboard → Upload Resume</p>
        </div>
      )}

      {/* Refresh Button */}
      <button 
        onClick={() => resumeText && analyzeResume(resumeText)}
        disabled={loading}
        style={{
          marginTop: '20px',
          padding: '10px 20px',
          background: '#007bff',
          color: 'white',
          border: 'none',
          borderRadius: '5px',
          cursor: loading ? 'not-allowed' : 'pointer'
        }}
      >
        {loading ? '🤖 Analyzing...' : '🔄 Refresh Recommendations'}
      </button>
    </div>
  );
};

export default AIDashboard;
